import React, { useRef, useEffect, useState } from "react";
import { getImage } from "../../utils/getImage";

export default function Lightbox({
  selected,
  isOpen,
  onClose,
  onNext,
  onPrev,
  isMobile,
  zoom,
  setZoom,
}) {
  const lightboxRef = useRef(null);
  const touchStartX = useRef(0);
  const touchEndX = useRef(0);

  // Focus trap
  useEffect(() => {
    if (isOpen && lightboxRef.current) {
      lightboxRef.current.focus();
    }
  }, [isOpen]);

  // Swipe handlers
  const handleTouchStart = (e) => {
    touchStartX.current = e.touches[0].clientX;
  };

  const handleTouchMove = (e) => {
    touchEndX.current = e.touches[0].clientX;
  };

  const handleTouchEnd = () => {
    const diff = touchStartX.current - touchEndX.current;
    const threshold = 50; // px mínimos para considerar swipe

    if (Math.abs(diff) > threshold) {
      if (diff > 0) {
        onNext();
      } else {
        onPrev();
      }
    }

    // Reset
    touchStartX.current = 0;
    touchEndX.current = 0;
  };

  if (!isOpen || !selected) return null;

  return (
    <div
      ref={lightboxRef}
      role="dialog"
      aria-modal="true"
      aria-label={`Vista ampliada de ${selected.titulo}`}
      tabIndex={-1}
      onClick={onClose}
      onTouchStart={handleTouchStart}
      onTouchMove={handleTouchMove}
      onTouchEnd={handleTouchEnd}
      style={{
        position: "fixed",
        inset: 0,
        background: "rgba(0,0,0,0.95)",
        display: "flex",
        flexDirection: "column",
        alignItems: "center",
        justifyContent: "center",
        zIndex: 999,
        touchAction: "pan-y",
      }}
    >
      {/* CONTENEDOR IMAGEN */}
      <div
        style={{
          display: "flex",
          alignItems: "center",
          justifyContent: "center",
          width: "100%",
          flex: 1,
          position: "relative",
        }}
      >
        {/* FLECHA IZQUIERDA */}
        <button
          onClick={(e) => {
            e.stopPropagation();
            onPrev();
          }}
          style={arrowStyle("left", isMobile)}
          aria-label="Anterior"
        >
          ‹
        </button>

        {/* IMAGEN */}
        <img
          src={getImage(selected, "full")}
          alt={selected.titulo}
          onClick={(e) => e.stopPropagation()}
          onDoubleClick={(e) => {
            e.stopPropagation();
            setZoom((z) => !z);
          }}
          draggable={false}
          style={{
            maxWidth: isMobile ? "90%" : "75%",
            maxHeight: zoom ? "none" : "80vh",
            borderRadius: "12px",
            transform: zoom ? "scale(1.8)" : "scale(1)",
            transition: "transform 0.3s ease",
            cursor: zoom ? "zoom-out" : "zoom-in",
            userSelect: "none",
            pointerEvents: "auto",
          }}
        />

        {/* FLECHA DERECHA */}
        <button
          onClick={(e) => {
            e.stopPropagation();
            onNext();
          }}
          style={arrowStyle("right", isMobile)}
          aria-label="Siguiente"
        >
          ›
        </button>
      </div>

      {/* FOOTER CON TÍTULO + DESCARGA */}
      <div
        style={{
          width: "100%",
          padding: "16px",
          background: "rgba(0,0,0,0.8)",
          color: "#fff",
          textAlign: "center",
        }}
      >
        <h3 style={{ margin: 0, fontFamily: "'Montserrat', sans-serif" }}>
          {selected.titulo}
        </h3>
        <p
          style={{
            margin: "4px 0 12px",
            opacity: 0.7,
            fontFamily: "'Montserrat', sans-serif",
          }}
        >
          {selected.descripcion}
        </p>

        {/* BOTÓN DESCARGAR */}
        <a
          href={getImage(selected, "full")}
          download={`${selected.titulo}.png`}
          onClick={(e) => e.stopPropagation()}
          style={{
            display: "inline-block",
            padding: "6px 16px",
            borderRadius: "6px",
            border: "1px solid rgba(255,255,255,0.5)",
            background: "transparent",
            color: "#fff",
            fontSize: "12px",
            textDecoration: "none",
            cursor: "pointer",
            fontFamily: "'Montserrat', sans-serif",
            transition: "all 0.2s ease",
          }}
          onMouseEnter={(e) => {
            e.currentTarget.style.background = "rgba(255,255,255,0.15)";
          }}
          onMouseLeave={(e) => {
            e.currentTarget.style.background = "transparent";
          }}
        >
          Descargar
        </a>
      </div>
    </div>
  );
}

function arrowStyle(side, isMobile) {
  return {
    position: "absolute",
    [side]: "10px",
    top: "50%",
    transform: "translateY(-50%)",
    width: "48px",
    height: "48px",
    display: "flex",
    alignItems: "center",
    justifyContent: "center",
    fontSize: "36px",
    color: "rgba(255,255,255,0.8)",
    background: "rgba(0,0,0,0.3)",
    border: "none",
    borderRadius: "50%",
    cursor: "pointer",
    zIndex: 10,
    transition: "background 0.2s ease",
  };
}
